<?php/*    Power Vs Wind Speed    Formatted to match Power_Vs_Wind_Speed_renom.php.*/if (!function_exists('pws_escape_value')) {    function pws_escape_value($db, $value) {        return method_exists($db, 'real_escape_string') ? $db->real_escape_string($value) : addslashes($value);    }}if (!function_exists('pws_identifier')) {    function pws_identifier($value, $default) {        $value = (string)$value;        return preg_match('/^[A-Za-z0-9_]+$/', $value) ? $value : $default;    }}if (!function_exists('pws_h')) {    function pws_h($value) {        return htmlspecialchars((string)$value, ENT_QUOTES, 'UTF-8');    }}if (!function_exists('pws_num')) {    function pws_num($value) {        return ($value !== '' && $value !== null && is_numeric($value)) ? (float)$value : 0;    }}if (!function_exists('pws_format')) {    function pws_format($value, $decimals = 2) {        return number_format(pws_num($value), $decimals, '.', '');    }}if (!function_exists('pws_download_href')) {    function pws_download_href($FType) {        $query = isset($_SERVER['QUERY_STRING']) ? $_SERVER['QUERY_STRING'] : '';        if ($FType == 1 || $FType == 6) {            return 'channel2_ajax.php?'.$query.'&XLS=1';        }        if ($FType == 2) {            return 'channel3_ajax.php?'.$query.'&XLS=1';        }        if ($FType == 3) {            return 'channel4_ajax.php?'.$query.'&XLS=1';        }        if ($FType == 4) {            return 'channel5_ajax.php?'.$query.'&XLS=1';        }        if ($FType == 7 || $FType == 8) {            return 'channel8_ajax.php?'.$query.'&XLS=1';        }        if ($FType == 9 && (!isset($GLOBALS['Cook_Variable'][0]) || $GLOBALS['Cook_Variable'][0] != 'tirumala')) {            return 'channel9new_ajax.php?'.$query.'&XLS=1';        }        if ($FType == 10) {            return 'channel10_ajax.php?'.$query.'&XLS=1';        }        if ($FType == 11) {            return 'reports11_ajax.php?'.$query.'&XLS=1';        }        return '';    }}$Report_Title = 'Power Vs Wind Speed Report';$Report_FType = isset($FType) ? $FType : (isset($Format_Type) ? $Format_Type : 0);$Download_Href = pws_download_href($Report_FType);$Report_Database = isset($Database_Name) && $Database_Name != '' ? $Database_Name : (isset($Cook_Variable[7]) ? $Cook_Variable[7] : '');$Report_Table = isset($Table_Name) && $Table_Name != '' ? $Table_Name : '';$Report_Database_SQL = pws_identifier($Report_Database, '');$Report_Table_SQL = pws_identifier($Report_Table, '');$Report_Table_Ref = $Report_Database_SQL != '' && $Report_Table_SQL != '' ? $Report_Database_SQL.'.'.$Report_Table_SQL : '';$Report_Device_Name = '';if (isset($Device_Name) && !is_array($Device_Name) && $Device_Name != '') {    $Report_Device_Name = $Device_Name;}elseif (isset($Device_Name) && is_array($Device_Name)) {    if (isset($Device_Name[$IMEI]) && $Device_Name[$IMEI] != '') {        $Report_Device_Name = $Device_Name[$IMEI];    }    elseif (isset($Device_Name[1]) && $Device_Name[1] != '') {        $Report_Device_Name = $Device_Name[1];    }}if ($Report_Device_Name == '' && isset($All_Devicename[1]) && $All_Devicename[1] != '') {    $Report_Device_Name = $All_Devicename[1];}if ($Report_Device_Name == '') {    $Report_Device_Name = isset($IMEI) ? $IMEI : '';}?><?php if ($XLS == 0) { ?><style>    .pws-download-cell {        padding: 10px 0 12px;        text-align: right;    }    .pws-download-actions {        display: flex;        justify-content: flex-end;        gap: 10px;        flex-wrap: wrap;    }    .pws-download-btn,    .pws-pdf-btn {        display: inline-block;        padding: 8px 14px;        border: 1px solid #1d4ed8;        border-radius: 6px;        background: #1d4ed8;        color: #fff !important;        font-size: 12px;        font-weight: 700;        letter-spacing: 0;        text-decoration: none;        cursor: pointer;        font-family: Arial, Helvetica, sans-serif;        line-height: normal;    }    .pws-pdf-btn {        border-color: #0f8f6f;        background: #0f8f6f;    }    .pws-report-table {        width: 100%;        border-collapse: separate;        border-spacing: 0;        overflow: hidden;        border: 1px solid #d7dee8;        border-radius: 8px;        background: #fff;        font-family: Arial, Helvetica, sans-serif;        box-shadow: 0 10px 24px rgba(15, 23, 42, 0.08);    }    .pws-title-cell {        padding: 16px 18px;        border-bottom: 1px solid #d7dee8;        background: #f8fafc;        color: #0f172a;    }    .pws-title-wrap {        display: flex;        align-items: center;        justify-content: space-between;        gap: 12px;        flex-wrap: wrap;    }    .pws-title {        font-size: 18px;        font-weight: 700;    }    .pws-subtitle {        color: #475569;        font-size: 12px;        font-weight: 700;    }    .pws-summary-cell {        padding: 12px 14px;        border-bottom: 1px solid #e2e8f0;        background: #ffffff;    }    .pws-summary-grid {        display: grid;        grid-template-columns: repeat(4, minmax(130px, 1fr));        gap: 10px;    }    .pws-summary-item {        min-height: 54px;        padding: 9px 11px;        border: 1px solid #e2e8f0;        border-radius: 6px;        background: #f8fafc;    }    .pws-summary-label {        display: block;        color: #64748b;        font-size: 11px;        font-weight: 700;        text-transform: uppercase;    }    .pws-summary-value {        display: block;        margin-top: 4px;        color: #0f172a;        font-size: 15px;        font-weight: 700;    }    .pws-head-cell {        padding: 10px 12px;        border-bottom: 1px solid #cbd5e1;        background: #1e293b;        color: #ffffff;        font-size: 12px;        font-weight: 700;        text-align: left;        white-space: nowrap;    }    .pws-body-cell {        padding: 8px 12px;        border-bottom: 1px solid #e5e7eb;        color: #1f2937;        font-size: 12px;        text-align: left;    }    .pws-num {        text-align: right;        font-variant-numeric: tabular-nums;    }    .pws-report-table tr:nth-child(even) .pws-body-cell {        background: #f9fbfd;    }    .pws-empty-cell {        padding: 16px;        border: 1px solid #d7dee8;        background: #fff7ed;        color: #9a3412;        font-size: 13px;        font-weight: 700;        text-align: center;    }    @media (max-width: 760px) {        .pws-summary-grid {            grid-template-columns: repeat(2, minmax(130px, 1fr));        }        .pws-head-cell,        .pws-body-cell {            padding: 8px;            font-size: 11px;        }    }    @media print {        .pws-download-cell {            display: none !important;        }    }</style><tr>    <td colspan="5" class="pws-download-cell">        <div class="pws-download-actions">            <?php if ($Download_Href != '') { ?>                <a href="<?= pws_h($Download_Href) ?>" class="pws-download-btn">Download Excel</a>            <?php } ?>            <button type="button" class="pws-pdf-btn" onclick="window.print()">Download PDF</button>        </div>    </td></tr><?php } ?><tr>    <td height="5px">&nbsp;</td></tr><tr>    <td width="100%">        <table width="100%" border="<?= $XLS == 1 ? '1' : '0' ?>" align="left" cellpadding="1" cellspacing="1" class="innertab1 pws-report-table">            <?php if ($XLS == 1) { ?>            <tr>                <td class="tab-head-tr" colspan="4" align="center"><b><?= pws_h($Report_Title) ?> - <?= pws_h($Report_Device_Name) ?></b></td>            </tr>            <tr>                <td class="tab-head-td" align="left" width="25%"><b>Device Name</b></td>                <td class="tab-head-td" align="left" width="25%"><b><?= pws_h($Report_Device_Name) ?></b></td>                <td class="tab-head-td" align="left" width="25%"><b>WEG No</b></td>                <td class="tab-head-td" align="left" width="25%"><b><?= pws_h(isset($All_WEG_No[1]) ? $All_WEG_No[1] : '') ?></b></td>            </tr>            <tr>                <td class="tab-head-td" align="left"><b>Site Location</b></td>                <td class="tab-head-td" align="left"><b><?= pws_h(isset($Site_Location[1]) ? $Site_Location[1] : '') ?></b></td>                <td class="tab-head-td" align="left"><b>LOC No</b></td>                <td class="tab-head-td" align="left"><b><?= pws_h(isset($All_LOC_No[1]) ? $All_LOC_No[1] : '') ?></b></td>            </tr>            <tr>                <td class="tab-head-td" align="left"><b>DOCS</b></td>                <td class="tab-head-td" align="left"><b><?= pws_h(isset($DOC[1]) ? $DOC[1] : '') ?></b></td>                <td class="tab-head-td" align="left"><b>HTSC No</b></td>                <td class="tab-head-td" align="left"><b><?= pws_h(isset($All_HTSC_No[1]) ? $All_HTSC_No[1] : '') ?></b></td>            </tr>            <tr style="border:0px"><td colspan="4">&nbsp;</td></tr>            <?php } ?>            <?php if ($XLS == 0) { ?>            <tr>                <td class="pws-title-cell" colspan="4">                    <div class="pws-title-wrap">                        <span class="pws-title"><?= pws_h($Report_Title) ?></span>                        <span class="pws-subtitle">Device Name: <?= pws_h($Report_Device_Name) ?></span>                    </div>                </td>            </tr>            <?php } ?>            <?php            if (isset($_REQUEST['p']) && $_REQUEST['p'] == 1) {                $IMEI_SQL = pws_escape_value($db, $IMEI);                $From_YMD_SQL = pws_escape_value($db, $From_YMD);                $To_YMD_SQL = pws_escape_value($db, $To_YMD);                if ($Report_Table_Ref == '') {                    die('Report table is not configured');                }                if ($Report_FType == 11) {                    $Pow_Windspeed_Query = "                        SELECT                            Bridge2_dcc AS Power,                            Bridge1_dcv AS Windspeed,                            Date_S,                            Time_S                        FROM ".$Report_Table_Ref."                        WHERE IMEI = '".$IMEI_SQL."'                          AND Date_S >= '".$From_YMD_SQL."'                          AND Date_S <= '".$To_YMD_SQL."'                        ORDER BY Date_S DESC, Time_S DESC";                }                else {                    $Pow_Windspeed_Query = "                        SELECT                            Power,                            Windspeed,                            Date_S,                            Time_S                        FROM ".$Report_Table_Ref."                        WHERE IMEI = '".$IMEI_SQL."'                          AND Date_S >= '".$From_YMD_SQL."'                          AND Date_S <= '".$To_YMD_SQL."'                        ORDER BY Date_S DESC, Time_S DESC";                }                if (!($Mysql_Query_Result = $db->query($Pow_Windspeed_Query))) {                    die($db->error);                }                $Power_Wind_Rows = array();                $Summary_Power_Total = 0;                $Summary_Wind_Total = 0;                $Summary_Power_Count = 0;                $Summary_Wind_Count = 0;                while ($Fetch_Result = $Mysql_Query_Result->fetch_array()) {                    $Power_Value = pws_num($Fetch_Result['Power']);                    $Wind_Value = pws_num($Fetch_Result['Windspeed']);                    $Summary_Power_Total += $Power_Value;                    $Summary_Wind_Total += $Wind_Value;                    $Summary_Power_Count++;                    $Summary_Wind_Count++;                    $Power_Wind_Rows[] = $Fetch_Result;                }                if (count($Power_Wind_Rows) >= 1) {                    $Summary_Avg_Power = $Summary_Power_Count > 0 ? ($Summary_Power_Total / $Summary_Power_Count) : 0;                    $Summary_Avg_Wind = $Summary_Wind_Count > 0 ? ($Summary_Wind_Total / $Summary_Wind_Count) : 0;                    ?>                    <?php if ($XLS == 0 && isset($_REQUEST['p']) && $_REQUEST['p'] == 56) { ?>                    <tr>                        <td colspan="4" class="pws-summary-cell">                            <div class="pws-summary-grid">                                <div class="pws-summary-item">                                    <span class="pws-summary-label">Records</span>                                    <span class="pws-summary-value"><?= count($Power_Wind_Rows) ?></span>                                </div>                                <div class="pws-summary-item">                                    <span class="pws-summary-label">Avg Wind Speed</span>                                    <span class="pws-summary-value"><?= pws_format($Summary_Avg_Wind, 2) ?> m/s</span>                                </div>                                <div class="pws-summary-item">                                    <span class="pws-summary-label">Avg Power</span>                                    <span class="pws-summary-value"><?= pws_format($Summary_Avg_Power, 2) ?> kW</span>                                </div>                                <div class="pws-summary-item">                                    <span class="pws-summary-label">Period</span>                                    <span class="pws-summary-value"><?= pws_h($From_YMD) ?> to <?= pws_h($To_YMD) ?></span>                                </div>                            </div>                        </td>                    </tr>                    <?php } ?>                    <tr>                        <td class="<?= $XLS == 1 ? 'tab-head-td' : 'pws-head-cell' ?>" width="80px" align="left"><b>Date</b></td>                        <td class="<?= $XLS == 1 ? 'tab-head-td' : 'pws-head-cell' ?>" width="80px" align="left"><b>Time</b></td>                        <td class="<?= $XLS == 1 ? 'tab-head-td' : 'pws-head-cell pws-num' ?>" width="90px" align="left"><b>Power</b> kW</td>                        <td class="<?= $XLS == 1 ? 'tab-head-td' : 'pws-head-cell pws-num' ?>" width="90px" align="left"><b>Wind Speed</b> m/s</td>                    </tr>                    <?php foreach ($Power_Wind_Rows as $Fetch_Result) { ?>                        <tr>                            <td class="<?= $XLS == 1 ? 'tab-head-td1' : 'pws-body-cell' ?>" align="left"><?= $Fetch_Result['Date_S'] != '' ? pws_h($Fetch_Result['Date_S']) : '0' ?></td>                            <td class="<?= $XLS == 1 ? 'tab-head-td1' : 'pws-body-cell' ?>" align="left"><?= $Fetch_Result['Time_S'] != '' ? pws_h($Fetch_Result['Time_S']) : '0' ?></td>                            <td class="<?= $XLS == 1 ? 'tab-head-td1' : 'pws-body-cell pws-num' ?>" align="left"><?= pws_format($Fetch_Result['Power'], 2) ?></td>                            <td class="<?= $XLS == 1 ? 'tab-head-td1' : 'pws-body-cell pws-num' ?>" align="left"><?= pws_format($Fetch_Result['Windspeed'], 2) ?></td>                        </tr>                    <?php } ?>                <?php }                else { ?>                    <tr>                        <td colspan="4" class="<?= $XLS == 1 ? 'tab-head-td1' : 'pws-empty-cell' ?>"><?= isset($No_Records) ? pws_h($No_Records) : 'No records found' ?></td>                    </tr>                <?php }            } ?>        </table>    </td></tr>